1	/** Coordinates of a live cell as [x, y]. */
2	export type Cell = [number, number];
3	
4	const key = ([x, y]: Cell): string => `${x},${y}`;
5	
6	const NEIGHBOR_OFFSETS: Cell[] = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1,  0],          [1,  0],
9	  [-1,  1], [0,  1], [1,  1],
10	];
11	
12	const countLiveNeighbors = ([x, y]: Cell, liveSet: Set<string>): number =>
13	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(key([x + dx, y + dy]))).length;
14	
15	export function nextGeneration(liveCells: Cell[]): Cell[] {
16	  const liveSet = new Set(liveCells.map(key));
17	  const candidates = new Map<string, Cell>();
18	  const addCandidate = (cell: Cell): void => { candidates.set(key(cell), cell); };
19	  for (const [x, y] of liveCells) {
20	    addCandidate([x, y]);
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) addCandidate([x + dx, y + dy]);
22	  }
23	  const result: Cell[] = [];
24	  for (const [k, cell] of candidates) {
25	    const n = countLiveNeighbors(cell, liveSet);
26	    if (n === 3 || (n === 2 && liveSet.has(k))) result.push(cell);
27	  }
28	  return result;
29	}
