const countLiveNeighbors = ([x, y]: Cell, liveSet: Set<string>): number =>
  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(key([x + dx, y + dy]))).length;

const isAliveNextGeneration = (liveNeighbors: number, isCurrentlyAlive: boolean): boolean =>
  liveNeighbors === 3 || (liveNeighbors === 2 && isCurrentlyAlive);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(key));
  const candidates = new Map<string, Cell>();
  const addCandidate = (cell: Cell): void => { candidates.set(key(cell), cell); };
  for (const [x, y] of liveCells) {
    addCandidate([x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) addCandidate([x + dx, y + dy]);
  }
  const result: Cell[] = [];
  for (const [k, cell] of candidates) {
    if (isAliveNextGeneration(countLiveNeighbors(cell, liveSet), liveSet.has(k))) {
      result.push(cell);
    }
  }
  return result;
}
